INSERT INTO public.charter_config (config_key, payload, updated_at)
VALUES ('sights_main_config', '{"routes":[{"id":"r2234","icon":"👑","name":"Королевский Пхукет","group":"Полдня","days":0.5,"mgrAdult":1500,"mgrChild":1000,"mgrInfant":0,"sellAdult":1500,"sellChild":1000,"netAdult":0,"netChild":0,"duration":"~08:00-16:00","groupSize":"~11","transport":"комфортный минивэн","guide":"Русскоговорящий","meals":"—","description":"Авторская обзорная: Королевская аптека Моринга, Храм Ранг Хилл, Розовое кафе, ул. Таланг Роуд, набережная Панва, смотровая Као Кад 360°, Галерея Самоцветов, Королевский Павильон Самоцветов.","program":["Трансфер из отеля (08:00)","Королевская аптека Моринга","Улица Таланг Роуд (китайско-португальская архитектура)","Храм Ранг Хилл (Сайсин — священная нить)","Розовое кафе","Набережная Панва","Смотровая площадка Као Кад 360°","Ювелирная фабрика «Галерея Самоцветов»","Королевский Павильон Самоцветов (фото в тайских нарядах)","Возвращение в отель (~16:00)"],"included":["Трансфер из отеля и обратно","Русский гид","Медстраховка"],"color":"#a78bfa","excursId":2234,"provider":"Остров Сокровищ"},{"id":"r1833","icon":"🛍️","name":"Шопинг-тур с гидом","group":"Полдня","days":0.5,"mgrAdult":0,"mgrChild":0,"mgrInfant":0,"sellAdult":0,"sellChild":0,"netAdult":0,"netChild":0,"duration":"~08:00-15:00","groupSize":"~11","transport":"комфортный минивэн","guide":"Русскоговорящий","meals":"—","description":"Шопинг по лучшим магазинам и фабрикам Пхукета: латекс, орешки кешью, жемчуг, ювелирка, акулий центр, бонусом — храм Ват Чалонг.","program":["Трансфер из отеля","Центр изделий из натурального латекса","Змеиная ферма и центр змеиной медицины","Фабрика по переработке орехов кешью","Жемчужная ферма","Ювелирный центр Gems Gallery","Центр Красоты и Здоровья","Центр препаратов из субпродуктов акулы","Храм Wat Chalong (бонус)","Возвращение в отель"],"included":["Трансфер из отеля и обратно","Русский гид","Медстраховка"],"color":"#a78bfa","excursId":1833,"provider":"Остров Сокровищ"},{"id":"r2546","icon":"🌃","name":"Реальный Пхукет + Пятничный рынок (север)","group":"Полдня","days":0.5,"mgrAdult":1500,"mgrChild":1000,"mgrInfant":0,"sellAdult":1500,"sellChild":1000,"netAdult":0,"netChild":0,"duration":"~10:00-20:30","groupSize":"~11","transport":"комфортный минивэн","guide":"Русскоговорящий","meals":"—","description":"Авторская обзорная для туристов с севера Пхукета (Майкао, Найтон, Бангтао, Най Янг, Лаян). Пляж с самолётами, Белый храм, Храм закопанного Будды, Аптека Моринга, Пятничный вечерний рынок.","program":["Трансфер из отелей (10:00-11:30)","Пляж с самолётами (12:00-13:00)","Белый храм Wat Kanan (13:30-14:30)","Храм закопанного Будды Wat Phra Thong (14:40-15:10)","Королевская аптека Моринга (15:40-16:40)","Пятничный вечерний рынок Friday Avenue Market (17:00-19:00)","Возвращение в отели (20:30)"],"included":["Трансфер с севера Пхукета","Русский гид","Медстраховка"],"color":"#a78bfa","excursId":2546,"provider":"Остров Сокровищ"},{"id":"r2547","icon":"🌆","name":"Реальный Пхукет + Субботний рынок (юг)","group":"Полдня","days":0.5,"mgrAdult":1500,"mgrChild":1000,"mgrInfant":0,"sellAdult":1500,"sellChild":1000,"netAdult":0,"netChild":0,"duration":"~11:00-21:30","groupSize":"~11","transport":"комфортный минивэн","guide":"Русскоговорящий","meals":"—","description":"Авторская обзорная для туристов с юга Пхукета (Чалонг, Равай, Найхарн, Ката, Карон, Патонг, Калим). Большой Будда, смотровая Ранг Хилл, Старый город, Као Ранг, змеиная ферма, Субботний рынок.","program":["Трансфер из отелей (11:00-12:00)","Храм Большой Будда (12:30-13:00)","Змеиная ферма PH+, шоу с кобрами (13:30-14:30)","Старый город Пхукет, прогулка, обед самостоятельно (15:00-16:00)","Смотровая Ранг Хилл (16:30-16:50)","Храмовый комплекс Као Ранг (17:00-17:30)","Субботний рынок Weekend Naka Market (18:00-20:00)","Возвращение в отели (21:30)"],"included":["Трансфер с юга Пхукета","Русский гид","Медстраховка"],"color":"#a78bfa","excursId":2547,"provider":"Остров Сокровищ"},{"id":"r1540","icon":"🗺️","name":"Реальный Пхукет (классика)","group":"Полдня","days":0.5,"mgrAdult":1000,"mgrChild":800,"mgrInfant":0,"sellAdult":1000,"sellChild":800,"netAdult":0,"netChild":0,"duration":"~08:45-16:00","groupSize":"~20","transport":"минивэн / минибас","guide":"Русскоговорящий","meals":"—","description":"Полная классическая обзорка: смотровые Karon Viewpoint, Ветряки, Промтеп, Ранг Хилл; рынок морских цыган Чао Ле, Большой Будда, Ват Чалонг, улица тайского бокса, Старый город, кормление обезьян и слонёнка.","program":["Встреча в отеле (08:45)","Karon Viewpoint — 3 пляжа","Смотровая «Ветряная Мельница»","Мыс Промтеп","Рынок морских цыган Чао Ле","Смотровая у статуи Большого Будды","Кормление слонёнка, фото","Храм Ват Чалонг","Улица тайского бокса","Старый город Пхукет","Смотровая Ранг Хилл, кормление обезьян","Возвращение в отель (15:00)"],"included":["Трансфер из отеля","Русский гид (только в автобусе)","Медстраховка"],"color":"#a78bfa","excursId":1540,"provider":"Остров Сокровищ"},{"id":"r1192","icon":"🦜","name":"Дискавери (для семей с детьми)","group":"Полдня","days":0.5,"mgrAdult":2200,"mgrChild":2000,"mgrInfant":0,"sellAdult":2200,"sellChild":2000,"netAdult":0,"netChild":0,"duration":"~08:00-15:00","groupSize":"~11","transport":"комфортный минивэн","guide":"Русскоговорящий","meals":"—","description":"Знакомство с животным миром Таиланда. Парк птиц, крокодиловая ферма с шоу, змеиная ферма с кобрами и питонами, кормление слонёнка. Идеально для детей.","program":["Трансфер из отелей юга (08:00)","Phuket Bird Park (12 га, шоу с птицами)","Крокодиловая ферма (шоу 20 мин)","Змеиная ферма (шоу с кобрами и питоном, 10 мин)","Кормление слонёнка бананами","Возвращение в отели (~15:00)"],"included":["Трансфер с юга Пхукета","Русский гид","Все входные билеты и шоу","Корзинка для кормления слона","Медстраховка"],"color":"#a78bfa","excursId":1192,"provider":"Остров Сокровищ"},{"id":"r2270","icon":"🛒","name":"Будда шопинг-тур","group":"Полдня","days":0.5,"mgrAdult":900,"mgrChild":500,"mgrInfant":0,"sellAdult":900,"sellChild":500,"netAdult":0,"netChild":0,"duration":"~08:00-16:00","groupSize":"~11","transport":"комфортный минивэн","guide":"Русскоговорящий","meals":"—","description":"Шопинг с посещением Большого Будды. Royal Shark, Аптека Моринга, Big Buddha, ювелирка Princess, латексная фабрика, змеиная ферма, ТЦ Central Festival.","program":["Трансфер из отеля (08:00)","Royal Shark — оздоровительная продукция","Королевская аптека Moringa","Храм Big Buddha (панорама)","Princess Jewerly Phuket","Змеиная ферма и шоу","Латексная фабрика","ТЦ Central Festival (можно остаться или вернуться в отель)"],"included":["Трансфер из отеля","Русский гид","Медстраховка"],"color":"#a78bfa","excursId":2270,"provider":"Остров Сокровищ"},{"id":"r1980","icon":"🏯","name":"Реальный Пхукет (компакт)","group":"Полдня","days":0.5,"mgrAdult":1200,"mgrChild":800,"mgrInfant":0,"sellAdult":1200,"sellChild":800,"netAdult":0,"netChild":0,"duration":"~08:00-16:00","groupSize":"~11","transport":"комфортный минивэн","guide":"Русскоговорящий","meals":"—","description":"Компактная обзорная: Karon View Point, Большой Будда, змеиная ферма с шоу, Старый город, храм Као Ранг, Ранг Хилл.","program":["Трансфер из отелей (08:00)","Karon View Point (09:15)","Храмовый комплекс Большой Будда (10:00)","Змеиная ферма PH+, шоу с кобрами (11:15)","Старый город Пхукет, обед самостоятельно (12:45)","Храмовый комплекс Као Ранг (14:00)","Смотровая Ранг Хилл (14:40)","Возвращение в отели (15:00-16:00)"],"included":["Трансфер из отеля","Русский гид","Медстраховка"],"color":"#a78bfa","excursId":1980,"provider":"Остров Сокровищ"}],"items":[{"id":"i_tx_kl_ind","tId":"ALL","cat":"transfer","icon":"🚐","name":"Индивидуальный трансфер из Као Лак","type":"fixed","mgr":true,"mgrPrice":5000,"sell":5000,"net":0,"note":"за машину туда-обратно"},{"id":"i_tx_far","tId":"ALL","cat":"transfer","icon":"🚐","name":"Дальние районы (Панва / Ао По / Ко Сирей)","type":"fixed","mgr":true,"mgrPrice":2500,"sell":2500,"net":0,"note":"за машину туда-обратно"},{"id":"i_extra_hr","tId":"r1540","cat":"extra","icon":"⏱️","name":"Дополнительный час по запросу","type":"fixed","mgr":true,"mgrPrice":500,"sell":500,"net":0,"note":"за час"},{"id":"i_ph_croc","tId":"r1192","cat":"extra","icon":"🐊","name":"Фото с крокодилом","type":"per_pax","mgr":true,"mgrPrice":200,"sell":200,"net":0,"note":"опционально"},{"id":"i_ph_bird","tId":"r1192","cat":"extra","icon":"🦜","name":"Фото с птицами","type":"per_pax","mgr":true,"mgrPrice":200,"sell":200,"net":0,"note":"опционально"}]}'::jsonb, NOW())
