INSERT INTO public.charter_config (config_key, payload, updated_at)
VALUES ('individual_main_config', '{"routes":[{"id":"r2542","icon":"💆","name":"Природа и Нирвана","group":"1 день","days":1,"baseSell":15000,"extraPaxSell":2700,"inclusivePax":0,"baseNet":0,"extraPaxNet":0,"mgrBase":15000,"mgrExtraPax":2700,"duration":"1 день, ~08:00-19:30","groupSize":"11 человек","transport":"комфортный минивэн с кондиционером","guide":"Русскоговорящий","meals":"обед","description":"Белый храм Wat Kanan, смотровая площадка Самет Нангше, заповедник для слонов, деревня Каренов, обед в локальном ресторане и расслабление в Mantra Spa - день, наполненный природой, культурой и гармонией.","program":["08:00 Выезд из отеля.","09:30-10:00 Посещение Белого храма Wat Kanan, красивого","и редкого храма в","северной части Пхукета.","11:10-11:50 Смотровая площадка Самет Нангше с видом на","залив Пханг Нга.","12:10-13:00 Посещение слоновьего заповедника:","кормление, душ со слоном и","общение. Встреча с народом Карены, знакомство с их","традициями и ремёслами.","13:20-14:10 Обед в локальном ресторане Fashi.","14:30-17:30 Релакс-программа в Mantra Spa: бассейны,","сауны, термальные ванны и","зоны отдыха в окружении зелени.","18:30-19:30 Прибытие в отели."],"included":["Трансфер со всех районов Пхукета","Русскоговорящий гид","Питание по программе","Все входные билеты по программе","Шкафчик для хранения вещей, полотенце и бутылка воды","Медицинская страховка"],"color":"#fb923c","excursId":2542,"provider":"Остров Сокровищ"},{"id":"r2504","icon":"🏝️","name":"Пхи-Пхи + Джеймс Бонд","group":"1 день","days":1,"baseSell":45000,"extraPaxSell":2000,"inclusivePax":0,"baseNet":0,"extraPaxNet":0,"mgrBase":45000,"mgrExtraPax":2000,"duration":"1 день, ~08:00-18:00","groupSize":"18 человек","transport":"скоростная лодка speedboat","guide":"Русскоговорящий","meals":"обед","description":"Остров Джеймса Бонда, Као Пинг Кан, деревня Паньи, Майя Бэй, лагуна Пиле, пещера Викингов и Бухта Обезьян - насыщенное путешествие по главным природным и кинематографическим локациям Пханг Нга и Пхи-Пхи.","program":["может меняться в связи с погодными","условиями или другими непредвиденными","обстоятельствами.","дети до 1-го года и люди с проблемами спины и шеи.","Взять с собой","б рубашка с длинным рукавом или парео"],"included":["Трансфер","Русскоговорящий гид","Питание по программе","Стоимость указана за группу до 10-ти человек","Полотенце","Универсальные маски для снорклинга для взрослых","Катание на каноэ","Спасательные жилеты"],"color":"#fb923c","excursId":2504,"provider":"Остров Сокровищ"},{"id":"r2505","icon":"🏝️","name":"Пхи-Пхи и Бамбу","group":"1 день","days":1,"baseSell":43000,"extraPaxSell":2000,"inclusivePax":0,"baseNet":0,"extraPaxNet":0,"mgrBase":43000,"mgrExtraPax":2000,"duration":"1 день, ~08:00-18:00","groupSize":"18 человек","transport":"скоростная лодка speedboat","guide":"Русскоговорящий","meals":"обед","description":"Бухта Майя, лагуна Пиле, пещера Викингов, Бухта Обезьян, пляж Ло Му Ди и остров Бамбу - яркий маршрут с купанием, снорклингом и отдыхом на лучших локациях Пхи-Пхи.","program":["может меняться в связи с погодными","условиями или другими непредвиденными","обстоятельствами.","дети до 1-го года и люди с проблемами спины и шеи.","Взять с собой","б рубашка с длинным рукавом или парео"],"included":["Трансфер","Русскоговорящий гид","Питание по программе","Стоимость указана за группу до 10-ти человек","Полотенце","Универсальные маски для снорклинга для взрослых","Спасательные жилеты","Входные билеты в Национальный парк"],"color":"#fb923c","excursId":2505,"provider":"Остров Сокровищ"},{"id":"r2506","icon":"🏝️","name":"Пхи-Пхи + Джеймс Бонд + Краби 2 дня/1 ночь.","group":"2 дня / 1 ночь","days":2,"baseSell":65000,"extraPaxSell":3500,"inclusivePax":0,"baseNet":0,"extraPaxNet":0,"mgrBase":65000,"mgrExtraPax":3500,"duration":"2 дня/1 ночь, ~07:45-18:00","groupSize":"18 человек","transport":"скоростная лодка speedboat","guide":"Русскоговорящий","meals":"2 обеда, ужин","description":"Индивидуально Остров Панак, остров Джеймса Бонда, деревня Паньи, остров Хонг с панорамной площадкой, Пхи-Пхи Дон (Ло Лана), бухта Майя, лагуна Пиле, пещера Викингов, бухта Обезьян, Ло Му Ди и остров Бамбу - насыщённый двухдневный маршрут с фотостопами, снорклингом и отдыхом на лу","program":["может меняться в связи с погодными","условиями или другими непредвиденными","обстоятельствами.","дети до 1-го года и люди с проблемами спины и шеи.","Взять с собой","б рубашка с длинным рукавом или парео"],"included":["Трансфер","Русскоговорящий гид","Питание по программе","Проживание по программе","Стоимость указана за группу до 10-ти человек","Полотенце","Универсальные маски для снорклинга для взрослых","Катание на каноэ"],"color":"#fb923c","excursId":2506,"provider":"Остров Сокровищ"},{"id":"r2363","icon":"🐢","name":"Острова Рок и Ха 6","group":"1 день","days":1,"baseSell":60000,"extraPaxSell":3000,"inclusivePax":0,"baseNet":0,"extraPaxNet":0,"mgrBase":60000,"mgrExtraPax":3000,"duration":"1 день, ~04:00-17:00","groupSize":"35 человек","transport":"скоростная лодка speedboat","guide":"Русскоговорящий","meals":"завтрак-обед","description":"Маршрут для тех, кто видел много. Острова Ко Рок и Ко Ха, известные как Королевские острова, впечатляют прозрачной водой, уединенными пляжами и великолепным подводным миром, приятно поразят вас тишиной и уединенностью.","program":["04:00 Сбор по отелям, трансфер на пирс.","05:30 Прибытие на пирс, легкий завтрак.","06:00 Выезд на скоростном катере в сторону острова Рок.","08:30-11:30 Высадка на Ко Рок Яй: отдых на пляже,","снорклинг с пляжа.","Обед в крытом тайском кафе с видом на пляж. В меню","классический тайский сет:","рис, зеленое карри, жареная курица, жареная рыба,","тушеные овощи.","11:40-11:50 Осмотр острова Ко Рок Ной с лодки.","12:30-13:10 Снорклинг у Ко Ха.","14:45 Прибытие на Пхукет.","15:30 Трансфер в отели."],"included":["Трансфер со всех пляжей на Пхукете","Русскоговорящий гид","Питание по программе","Универсальные маски для снорклинга для взрослых","Спасательные жилеты","Медицинская страховка"],"color":"#fb923c","excursId":2363,"provider":"Остров Сокровищ"},{"id":"r2361","icon":"🌅","name":"Изумруды Краби 2д/1н","group":"2 дня / 1 ночь","days":2,"baseSell":30000,"extraPaxSell":5000,"inclusivePax":0,"baseNet":0,"extraPaxNet":0,"mgrBase":30000,"mgrExtraPax":5000,"duration":"2 дня/1 ночь, ~06:00-18:00","groupSize":"11 человек","transport":"минивэн + деревянная длиннохвостая лодка","guide":"Русскоговорящий","meals":"обед-ужин-завтрак-обед","description":"Двухдневный тур в Краби. Посещение пещеры Klang Cave, Изумрудного и Голубого озер, горячих источников, прогулка на лодке по островам Национального парка (Близнецы, Чикен, Пода), ночевка и отдых на пляже Ао Нанг. Идеально для любителей природы и ярких впечатлений!","program":["тура может изменяться в зависимости от","погодных условий, приливов и отливов.","Взять с собой","головной убор, х/б рубашка с длинным рукавом или парео"],"included":["Трансфер со всех районов Пхукета","Русскоговорящий гид","Проживание и питание по программе","Входные билеты в Национальный парк","Универсальные маски для снорклинга для взрослых","Спасательные жилет","Медицинская страховка"],"color":"#fb923c","excursId":2361,"provider":"Остров Сокровищ"},{"id":"r2132","icon":"🐠","name":"Симиланские острова (3 мотора)","group":"1 день","days":1,"baseSell":70000,"extraPaxSell":2500,"inclusivePax":10,"baseNet":0,"extraPaxNet":0,"mgrBase":70000,"mgrExtraPax":2500,"duration":"1 день, ~06:00-18:00","groupSize":"35 человек","transport":"скоростная лодка speedboat 3 мотора","guide":"Русскоговорящий","meals":"Завтрак на пирсе, обед, легкий ужин на пирсе по","description":"Симиланские острова входят в десятку самых красивых мест мира по версии ЮНЕСКО! Этот тур позволит насладиться белоснежными пляжами и кристально чистой водой.","program":["06:00 Выезд из отелей.","08:00 Прибытие на пирс: чай, кофе, выпечка.","09:00 Отправление на Симиланские острова на скоростном","катере.","Посещение островов №8 и №4, где находятся потрясающие","пляжи