-- ============================================================
-- VACATION PLANS — таблица для календаря отдыха (Этап 3)
-- ============================================================
CREATE TABLE IF NOT EXISTS public.vacation_plans (
  id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  created_by      UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  client_name     TEXT NOT NULL DEFAULT '',
  status          TEXT NOT NULL DEFAULT 'draft',  -- draft|sent|booked|completed
  date_from       DATE,
  date_to         DATE,
  pax             JSONB NOT NULL DEFAULT '{"adults":2,"children":0,"infants":0}',
  days            JSONB NOT NULL DEFAULT '[]',    -- [{date,title,parts:[],notes}, ...]
  total_sell      INT  NOT NULL DEFAULT 0,
  total_net       INT  NOT NULL DEFAULT 0,
  total_margin    INT  NOT NULL DEFAULT 0,
  pricing_snapshot JSONB NOT NULL DEFAULT '{}',
  notes           TEXT NOT NULL DEFAULT '',
  metadata        JSONB NOT NULL DEFAULT '{}',
  primary_calculation_id UUID REFERENCES public.calculations(id) ON DELETE SET NULL,
  created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  sent_at         TIMESTAMPTZ
);

CREATE INDEX IF NOT EXISTS idx_vp_creator    ON public.vacation_plans(created_by);
CREATE INDEX IF NOT EXISTS idx_vp_status     ON public.vacation_plans(status);
CREATE INDEX IF NOT EXISTS idx_vp_date_range ON public.vacation_plans(date_from, date_to);

ALTER TABLE public.vacation_plans ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "vp_select" ON public.vacation_plans;
DROP POLICY IF EXISTS "vp_insert" ON public.vacation_plans;
DROP POLICY IF EXISTS "vp_update" ON public.vacation_plans;
DROP POLICY IF EXISTS "vp_delete" ON public.vacation_plans;

CREATE POLICY "vp_select" ON public.vacation_plans FOR SELECT TO authenticated
  USING (created_by = auth.uid()
         OR EXISTS (SELECT 1 FROM public.user_roles WHERE user_id = auth.uid() AND role = 'booking'));
CREATE POLICY "vp_insert" ON public.vacation_plans FOR INSERT TO authenticated
  WITH CHECK (created_by = auth.uid());
CREATE POLICY "vp_update" ON public.vacation_plans FOR UPDATE TO authenticated
  USING (created_by = auth.uid()
         OR EXISTS (SELECT 1 FROM public.user_roles WHERE user_id = auth.uid() AND role = 'booking'));
CREATE POLICY "vp_delete" ON public.vacation_plans FOR DELETE TO authenticated
  USING (created_by = auth.uid()
         OR EXISTS (SELECT 1 FROM public.user_roles WHERE user_id = auth.uid() AND role = 'booking'));

SELECT 'vacation_plans table ready' AS msg;
